      inner_join<Order, "t2">("customer_id"_t1 == "customer_id"_t2) |
      inner_join<OrderItem, "t3">("order_id"_t2 == "order_id"_t3) |
      inner_join<Product, "t4">("product_id"_t3 == "product_id"_t4) |
      where("customer_id"_t1 == customer_id) |
