  return Update<ValueType, SetsType, ConditionType>{
      .sets_ = _u.sets_, .where_ = _where.condition};
}

auto operator()(const auto& _conn) const {
    return update_impl<ValueType, SetsType, WhereType>(_conn, sets_, where_);
