    if (!result) {
        throw std::runtime_error("Database query failed");
    }

    // Convert the result to the desired format
    std::vector<ValidatedProfile> validated_profiles;
    for (const auto& profile : *result) {
        validated_profiles.push_back({
            .user_id = profile.user_id,
            .trimmed_name = profile.name,  // Already trimmed in the query
            .trimmed_email = profile.email, // Already trimmed in the query
            .name_length = profile.name.length(),
            .email_length = profile.email.length()
        });
    }

    return validated_profiles;
}

}  // namespace trim_and_length_validation
