 * Description: This function tracks time metrics for each project, including day, month, year, hour, minute, second, and duration in days.
 * Returns: std::vector<TimeMetrics>.
 */
std::vector<TimeMetrics> project_time_tracking() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  auto conn = sqlite::connect("test_db.sqlite").value();

  const auto query =
      select_from<Project, "p">(
          col<"project_id", "p"> | as<"project_id">, col<"name", "p"> | as<"name">,
          day(col<"start_time", "t">) | as<"day">, month(col<"start_time", "t">) | as<"month">,
          year(col<"start_time", "t">) | as<"year">, hour(col<"start_time", "t">) | as<"hour">,
          minute(col<"start_time", "t">) | as<"minute">,
          second(col<"start_time", "t">) | as<"second">,
          days_between(col<"start_time", "t">, col<"end_time", "t">) | as<"duration_days">) |
      inner_join<TimeLog, "t">(col<"project_id", "p"> == col<"project_id", "t">) |
      to<std::vector<TimeMetrics>>;

  return query(conn).value();
}

}  // namespace project_time_tracking

